import { expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";

const AGENT_NS = `
  @component(#{ type: ComponentType.Agent })
  namespace Components.MyAgent;
`;

describe("@graph", () => {
  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_graph
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T017.T017_01
    it("sub-namespace inside @component Agent compiles without diagnostics", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @graph
          namespace Graph {}
        }
      `);
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T017.T017_02
    it("@graph at top level outside @component emits invalid-namespace-nesting", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @graph
        namespace OrphanGraph {}
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-nesting",
        message: /graph/,
      });
    });

    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_graph_authoring:Products.A10nBlueprintEngine.Features.GraphAuthoring.graph_in_agent:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_namespace_path:Products.A10nBlueprintEngine.Features.GraphAuthoring.graph_in_agent:must
    it("@graph inside non-Agent @component emits invalid-namespace-nesting", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{ type: ComponentType.Service })
        namespace Components.MyService {
          @graph
          namespace Graph {}
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-nesting",
        message: /graph/,
      });
    });
  });
});

describe("@node", () => {
  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_node
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T017.T017_07
    it("op inside @graph namespace compiles without diagnostics", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @graph
          namespace Graph {
            @node(#{ is_entrypoint: true }) op entry(input: string): void;
          }
        }
      `);
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T017.T017_08
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_graph_authoring:Products.A10nBlueprintEngine.Features.GraphAuthoring.node_in_graph:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_namespace_path:Products.A10nBlueprintEngine.Features.GraphAuthoring.node_in_graph:must
    it("@node outside @graph emits invalid-namespace-nesting", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @node op orphan(): void;
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-nesting",
        message: /node/,
      });
    });

    it("@node at global scope emits invalid-namespace-nesting", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @node op orphan(): void;
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-nesting",
        message: /node/,
      });
    });
  });
});

// a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_predict
describe("@predict", () => {
  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_predict
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T018.T018_01
    it("op with typed input and output inside @graph compiles without diagnostics", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          model ClassifyOutput { label: string; }

          @graph
          namespace Graph {
            @predict op classify(sectors: string, trajectory: string): ClassifyOutput;
          }
        }
      `);
    });
  });

  describe("invalid", () => {
    it("@predict outside @graph emits invalid-namespace-nesting", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          model ClassifyOutput { label: string; }
          @predict op classify(input: string): ClassifyOutput;
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-nesting",
        message: /predict/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T018.T018_02
    it("@predict returning plain string emits predict-untyped-output", async () => {
      // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_predict:Products.A10nBlueprintEngine.Features.PredictContextBoundary.predict_declares_output:must
      // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.decorator_product:Products.A10nBlueprintEngine.Features.PredictContextBoundary.predict_declares_output:must
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          @graph
          namespace Graph {
            @predict op classify(input: string): string;
          }
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/predict-untyped-output",
        message: /classify/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T018.T018_03
    it("@predict with non-derivable input fields compiles without diagnostics — predict_input_minimal (T018_03)", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          model SectorSummary { name: string; }
          model TrajectoryEntry { value: float32; }
          model ClassifyOutput { label: string; }

          @graph
          namespace Graph {
            @predict op classify(sectors: SectorSummary, trajectory: TrajectoryEntry): ClassifyOutput;
          }
        }
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T018.T018_12
    it("@predict with no strategy fields compiles without diagnostics — predict_no_strategy (T018_09)", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        @component(#{ type: ComponentType.Agent })
        namespace Components.MyAgent {
          model ClassifyOutput { label: string; }

          @graph
          namespace Graph {
            @predict op classify(sectors: string): ClassifyOutput;
          }
        }
      `);
    });
  });
});

describe("eval_fixes_input (T018_08)", () => {
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T018.T018_08
  it("eval Inputs model matching predict op input fields compiles without diagnostics", async () => {
    const runner = await Tester.createInstance();
    await runner.compile(`
      @component(#{ type: ComponentType.Agent })
      namespace Components.MyAgent {
        model ClassifyOutput { label: string; }

        @graph
        namespace Graph {
          @predict op classify(sectors: string, trajectory: string): ClassifyOutput;
        }

        @eval(#{ title: "Classify Eval" })
        namespace Evals.Classification.E001 {
          model Inputs { sectors: string; trajectory: string; }

          @signal(#{
            title: "label quality",
            method: SignalMethod.Probabilistic,
            criteria: "is label correct?",
            examples: #[]
          })
          @projects(Products.P.Features.F.task_has_id)
          op E001_01(): boolean;

          @scoring(#{
            formula: "E001_01",
            examples: #[],
            boundaryCases: #[]
          })
          @calls([E001_01])
          op Score(): float32;
        }
      }

      @feature
      namespace Products.P.Features.F {
        @invariant(#{ predicate: "task has id", why: "reason" })
        op task_has_id(): void;
      }
    `);
  });
});

